// 1) Insert 3 documents
db.employee.insertMany([
  { name: 'ABC', age: 35, position: 'Full Stack Developer', salary: 60000 },
  { name: 'PQR', age: 28, position: 'Full Stack Developer', salary: 45000 },
  { name: 'XYZ', age: 31, position: 'Tester', salary: 40000 }
])

// 2) Count employees where age != 35 AND position = 'Full Stack Developer'
db.employee.find({
  age: { $ne: 35 },
  position: 'Full Stack Developer'
}).count()

// 3) Update with upsert
db.employee.updateMany(
  { name: 'XYZ', age: 31 },
  { $set: { position: 'Software Developer' } },
  { upsert: true }
)

// 4) Display name and position of employee with lowest salary
db.employee.find({}, { name: 1, position: 1, _id: 0 }).sort({ salary: 1 }).limit(1)

// (1) select age,name from employee where status='active'
db.employee.find(
  { status: 'active' },
  { age: 1, name: 1, _id: 0 }
)

// (2) select * from employee where status!='active'
db.employee.find({ status: { $ne: 'active' } })

// (3) select name from employee order by age desc
db.employee.find({}, { name: 1, _id: 0 }).sort({ age: -1 })

// (4) select * from employee where status='active' or age=50
db.employee.find({
  $or: [ { status: 'active' }, { age: 50 } ]
})

// (1) Insert 3-4 records
db.employee.insertMany([
  { name: 'AAA', age: 30, joiningDate: new Date('2008-06-15') },
  { name: 'BBB', age: 45, joiningDate: new Date('2012-03-10') },
  { name: 'CCC', age: 35, joiningDate: new Date('2015-05-05') },
  { name: 'DDD', age: 28, joiningDate: new Date('2005-11-20') }
])

// (2) List employees who joined before 1st January 2010
db.employee.find({
  joiningDate: { $lt: new Date('2010-01-01') }
})

// (3) Update name to 'WWW' where joiningDate is '05-05-2015'
db.employee.updateMany(
  { joiningDate: new Date('2015-05-05') },
  { $set: { name: 'WWW' } }
)

// (1) Delete all records with joiningDate before 1st January 2010
db.employee.deleteMany({
  joiningDate: { $lt: new Date('2010-01-01') }
})

// (2) List all employees with age > 50
db.employee.find({ age: { $gt: 50 } })

// (3) List only the 1st employee with age > 60
db.employee.find({ age: { $gt: 60 } }).limit(1)

// (1) Update name to 'Senior citizen' for employees with age > 60
db.employee.updateMany(
  { age: { $gt: 60 } },
  { $set: { name: 'Senior citizen' } }
)

// (2) Update name to 'JKL' where age = 20, insert if not found (upsert)
db.employee.updateOne(
  { age: 20 },
  { $set: { name: 'JKL' } },
  { upsert: true }
)

// (3) Delete all senior citizens (age > 60) from collection
db.employee.deleteMany({ age: { $gt: 60 } })

// (1) Count employees with age >= 60
db.employee.find({ age: { $gte: 60 } }).count()

// (2) List employees named 'ABC', 'PQR', or 'XYZ' in descending name order
db.employee.find(
  { name: { $in: ['ABC', 'PQR', 'XYZ'] } }
).sort({ name: -1 })

// (3) List employees with age between 25 and 50, show only age field
db.employee.find(
  { age: { $gte: 25, $lte: 50 } },
  { _id: 0, name: 0, joiningDate: 0 }
)

