// 1. Group by branch and count students in each branch
db.student.aggregate([
  { $group: { _id: '$branch', totalStudents: { $sum: 1 } } }
])

// 2. Calculate average marks for each branch
db.student.aggregate([
  { $group: { _id: '$branch', avgMarks: { $avg: '$marks' } } }
])

// 3. Find highest marks in each branch
db.student.aggregate([
  { $group: { _id: '$branch', highestMarks: { $max: '$marks' } } }
])

// 4. Display only students who scored more than 75
db.student.aggregate([
  { $match: { marks: { $gt: 75 } } }
])

